then.script:
var policy = JSON.parse(mc.getProperty("policyPayload"));
var renewal = JSON.parse(mc.getProperty("renewalpayload"));
var coverageList = JSON.parse(mc.getProperty("coveragePayload") || "[]");

function safeNumber(v){
if(v==null || v=="") return null;
return Number(v);
}

function getRenewalVehicle(id){
return (renewal.vehicles || []).filter(v=>v.insurableObjectIdentifier==id)[0];
}

function getPolicyCoverages(id){
return coverageList.filter(v=>v.insurableObjectIdentifier==id);
}

var result = {
parties: policy.parties,
productCode: (policy.productCode || "").toUpperCase(),
termStartDate: renewal.proposedTermStartDate || policy.termStartDate,
termEndDate: renewal.proposedTermEndDate || policy.termEndDate,
policyPeriod: renewal.policyPeriod || policy.policyPeriod,
channel:"Sales",
driverDetails:(renewal.driverDetails || policy.driverDetails || []).map(function(d){
return{
    driverName:d.driverName,
    driverLicenseNumber:d.driverLicenseNumber,
    driverLicenseJurisdictionCode:d.driverLicenseJurisdictionCode,
    driverLicenseJurisdictionZipCode:d.driverLicenseJurisdictionZipCode,
    drivingExperienceYearCount:safeNumber(d.drivingExperienceYearCount),
    yearsLicensedCount:safeNumber(d.yearsLicensedCount),
    accidentCount:safeNumber(d.accidentCount),
    violationCount:safeNumber(d.violationCount)
}
}),
underWritingQuestions: renewal.underWritingQuestions || policy.underWritingQuestions,
insurableObjects:(policy.insurableObjects || []).map(function(po){

var renewalObj = getRenewalVehicle(po.insurableObjectIdentifier) || {};
var policyCov = getPolicyCoverages(po.insurableObjectIdentifier);

return {
insurableObjectTypeCode: po.insurableObjectTypeCode,
vehicle:{
    vehicleIdentificationNumber:po.vehicle.vehicleIdentificationNumber,
    vehicleMakeName:po.vehicle.vehicleMakeName,
    vehicleModelName:po.vehicle.vehicleModelName,
    bodyType:po.vehicle.bodyType,
    vehicleModelYear:safeNumber(po.vehicle.vehicleModelYear),
    vehicleTypeCode:po.vehicle.vehicleTypeCode,
    vehicleSafetyFeatureIndicator:po.vehicle.vehicleSafetyFeatureIndicator,
    vehicleAntiTheftIndicator:po.vehicle.vehicleAntiTheftIndicator,
    vehicleGaragingPostalCode:po.vehicle.vehicleGaragingPostalCode,
    annualMileage:safeNumber(
    renewalObj?.vehicles?.annualMileage
    || po.vehicle.annualMileage),
    ownershipTypeCode:po.vehicle.ownershipTypeCode,
    cc:safeNumber(po.vehicle.cc),
    vehicleValue:safeNumber(
    renewalObj?.vehicles?.vehicleValue
    || po.vehicle.vehicleValue),
    licenseState:po.vehicle.licenseState,
    licensePlateNumber:po.vehicle.licensePlateNumber,
    primaryVehicleUse:po.vehicle.primaryVehicleUse,
    travelRadiusFarm:safeNumber(po.vehicle.travelRadiusFarm),
    unrepairedDamage:po.vehicle.unrepairedDamage
},
coverages:policyCov
}
})
};

mc.setPayloadJSON(result);

var policy = JSON.parse(mc.getProperty("policyPayload") || "{}");
var renewal = JSON.parse(mc.getProperty("renewalpayload") || "{}");
var AcceptQuote = JSON.parse(mc.getProperty("AcceptQuotePayload") || "{}");
function notEmpty(v){ return v!=null && v!="" }

function safeStr(v){ return (v||"").toString() }

function genTxnId(id){ return "TXN-REN-" + safeStr(id) }

function extractTermNo(t){
return Number((t || "0").replace("TERM-",""));
}

function pad3(n){
if(n<10) return "00"+n;
if(n<100) return "0"+n;
return ""+n;
}

var renewalsArr = policy.renewals || [];

var lastTermNo = 0;
renewalsArr.forEach(function(r){
var n = extractTermNo(r.policyTermIdentifier);
if(n>lastTermNo) lastTermNo=n;
});

var nextTerm = "TERM-"+pad3(lastTermNo+1);

var newRenewal = {
renewalId:renewal.renewalId,
policyNumber: AcceptQuote.policyNumber,
policyTermIdentifier: nextTerm,
termSequenceNumber: renewalsArr.length+1,
transactionTypeCode:"RENEWAL",
transactionIdentifier: genTxnId(renewal.renewalId),
transactionStatusCode:"RENEWED",
termStatusCode:"RENEWED",
termStartDate: renewal.proposedTermStartDate,
termEndDate: renewal.proposedTermEndDate,
policyPeriod: renewal.policyPeriod || "1 years",
pricing: renewal.pricing
};

var output = {
currentPolicyTermIdentifier:nextTerm,
termStatusCode:"RENEWED",
renewals: renewalsArr.concat([newRenewal])
};

mc.setPayloadJSON(output);
